mapper.select:
SELECT /* PayInfoMapper.orgPayInfoList */ A.KFTC_EVIDENCE_SEQ /*증거파일 SEQ */ , A.RGST_DT /*등록일자*/ , A.VALID_DT /*유효일자*/ , B.CONTRACT_NUM /*계약번호*/ , B.BAN /*청구계정번호*/ , B.SUBSCRIBER_NO AS TEL_NO /*전화번호*/ , B.SUB_LINK_NAME AS CUST_NAME /*고객명*/ , B.SUB_STATUS /*상태*/ , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM /*상태명*/ , B.LST_COM_ACTV_DATE /*가입일자*/ , B.OPEN_AGNT_CD /*대리점코드*/ , B.OPEN_AGNT_CD || ' / ' ||FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM /*대리점명*/ , A.REGST_ID /*등록자ID*/ , A.REGST_DTTM /*등록일자*/ , A.RVISN_ID /*수정자ID*/ , A.RVISN_DTTM /*수정일자*/ --, A.REAL_FILE_PATH /*실 파일경로*/ , A.REAL_FILE_NM /*실 파일명*/ , NVL(A.REG_YN, 'N') AS REG_YN /*파일 등록 여부*/ , DECODE(NVL(A.REG_YN, 'N'), 'N' ,'미등록', '등록') AS REG_YN_NM /*파일 등록 여부*/ , A.EXT /*파일 확장자*/ , C.BAN_ADR_PRIMARY_LN AS ADDR /*고객주소*/ , SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ')), 1,6) AS USER_SSN /*생년월일*/ , C.BL_BILLING_METHOD /*납부방법코드*/ , FN_GET_CODENM('MSP0001', NVL(C.BL_BILLING_METHOD, '0001')) AS BL_BILLING_METHOD_NM /*납부방법명*/ , B.ON_OFF_TYPE /*온오프라인구분*/ , FN_GET_CODENM('RCP0007', NVL(B.ON_OFF_TYPE, '1')) AS ON_OFF_TYPE_NM /*온오프라인구분명*/ , A.APPROVAL_ID /*검증자ID*/ , FN_GET_USRNM(A.APPROVAL_ID) AS APPROVAL_ID_NM /*검증자명*/ , A.APPROVAL_MSG /*검증내역*/ , TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS APPROVAL_DT /*검증일시*/ , NVL(A.APPROVAL_CD, '0002') AS APPROVAL_CD /*검증결과*/ , FN_GET_CODENM('CMN0211', NVL(A.APPROVAL_CD, '0002')) AS APPROVAL_CD_NM /*검증결과명*/ , NVL(A.EVIDENCE_TYPE_CD, '0002') AS EVIDENCE_TYPE_CD /*파일유형*/ , FN_GET_CODENM('CMN0210', NVL(A.EVIDENCE_TYPE_CD, '0002')) AS EVI_CD_NM /*파일유형명*/ FROM CMN_KFTC_EVIDENCE A, MSP_JUO_SUB_INFO B, MSP_JUO_BAN_INFO C WHERE B.CONTRACT_NUM = A.CONTRACT_NUM(+) AND B.BAN = C.BAN(+) AND B.PPPO = 'PO'
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUBSCRIBER_NO = #{searchName}
AND NVL(A.REG_YN, 'N') = #{regYn}
AND B.LST_COM_ACTV_DATE BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.RGST_DT BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.VALID_DT BETWEEN #{searchStartDt} AND #{searchEndDt}
AND B.OPEN_AGNT_CD = #{orgnId}
ORDER BY B.LST_COM_ACTV_DATE DESC

SELECT /* PayInfoMapper.orgPayInfoList */ A.KFTC_EVIDENCE_SEQ /*증거파일 SEQ */ , A.RGST_DT /*등록일자*/ , A.VALID_DT /*유효일자*/ , B.CONTRACT_NUM /*계약번호*/ , B.BAN /*청구계정번호*/ , B.SUBSCRIBER_NO AS TEL_NO /*전화번호*/ , B.SUB_LINK_NAME AS CUST_NAME /*고객명*/ , B.SUB_STATUS /*상태*/ , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM /*상태명*/ , B.LST_COM_ACTV_DATE /*가입일자*/ , B.OPEN_AGNT_CD /*대리점코드*/ , B.OPEN_AGNT_CD || ' / ' ||FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM /*대리점명*/ , A.REGST_ID /*등록자ID*/ , A.REGST_DTTM /*등록일자*/ , A.RVISN_ID /*수정자ID*/ , A.RVISN_DTTM /*수정일자*/ --, A.REAL_FILE_PATH /*실 파일경로*/ , A.REAL_FILE_NM /*실 파일명*/ , NVL(A.REG_YN, 'N') AS REG_YN /*파일 등록 여부*/ , DECODE(NVL(A.REG_YN, 'N'), 'N' ,'미등록', '등록') AS REG_YN_NM /*파일 등록 여부*/ , A.EXT /*파일 확장자*/ , C.BAN_ADR_PRIMARY_LN AS ADDR /*고객주소*/ , SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ')), 1,6) AS USER_SSN /*생년월일*/ , C.BL_BILLING_METHOD /*납부방법코드*/ , FN_GET_CODENM('MSP0001', NVL(C.BL_BILLING_METHOD, '0001')) AS BL_BILLING_METHOD_NM /*납부방법명*/ , B.ON_OFF_TYPE /*온오프라인구분*/ , FN_GET_CODENM('RCP0007', NVL(B.ON_OFF_TYPE, '1')) AS ON_OFF_TYPE_NM /*온오프라인구분명*/ , A.APPROVAL_ID /*검증자ID*/ , FN_GET_USRNM(A.APPROVAL_ID) AS APPROVAL_ID_NM /*검증자명*/ , A.APPROVAL_MSG /*검증내역*/ , TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS APPROVAL_DT /*검증일시*/ , NVL(A.APPROVAL_CD, '0002') AS APPROVAL_CD /*검증결과*/ , FN_GET_CODENM('CMN0211', NVL(A.APPROVAL_CD, '0002')) AS APPROVAL_CD_NM /*검증결과명*/ , NVL(A.EVIDENCE_TYPE_CD, '0002') AS EVIDENCE_TYPE_CD /*파일유형*/ , FN_GET_CODENM('CMN0210', NVL(A.EVIDENCE_TYPE_CD, '0002')) AS EVI_CD_NM /*파일유형명*/ FROM CMN_KFTC_EVIDENCE A, MSP_JUO_SUB_INFO B, MSP_JUO_BAN_INFO C WHERE B.CONTRACT_NUM = A.CONTRACT_NUM(+) AND B.BAN = C.BAN(+) AND B.PPPO = 'PO'
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUBSCRIBER_NO = #{searchName}
AND NVL(A.REG_YN, 'N') = #{regYn}
AND B.LST_COM_ACTV_DATE BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.RGST_DT BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.VALID_DT BETWEEN #{searchStartDt} AND #{searchEndDt}
AND B.OPEN_AGNT_CD = #{orgnId}
ORDER BY B.LST_COM_ACTV_DATE DESC

SELECT /* PayInfoMapper.custmgmtLists */ A.CONTRACT_NUM , A.SUBSCRIBER_NO , A.SUB_STATUS , FN_GET_CODENM('MSP0003', A.SUB_STATUS) AS SUB_STATUS_NM , A.SUB_LINK_NAME , A.LST_COM_ACTV_DATE , FN_GET_ORGNM(A.OPEN_AGNT_CD) AS OPEN_AGNT_NM , A.BAN FROM MSP_JUO_SUB_INFO A WHERE PPPO = 'PO'
AND A.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND A.CONTRACT_NUM = #{searchName}
AND A.SUBSCRIBER_NO = #{searchName}
AND A.LST_COM_ACTV_DATE BETWEEN #{searchStartDt} AND #{searchEndDt}

/* PayInfoMapper.getCustomerInfo */
SELECT SUB.CONTRACT_NUM , SUB.SVC_CNTR_NO , SUB.SUB_STATUS , FN_GET_CODENM('RCP0037', SUB.SUB_STATUS) AS SUB_STATUS_NM , SUB.SUB_LINK_NAME , SUBSTR(CRYPTO_AES256.DEC_AES(CUS.CUSTOMER_SSN), 1, 6) AS BIRTH_DT , CASE WHEN SUBSTR(CRYPTO_AES256.DEC_AES(NVL(CUS.CUSTOMER_SSN, ' ')), 7, 1) IN ('1', '2', '5', '6') THEN '19' || SUBSTR(CRYPTO_AES256.DEC_AES(NVL(CUS.CUSTOMER_SSN, ' ')), 0, 6) WHEN SUBSTR(CRYPTO_AES256.DEC_AES(NVL(CUS.CUSTOMER_SSN, ' ')), 7, 1) IN ('3', '4', '7', '8') THEN '20' || SUBSTR(CRYPTO_AES256.DEC_AES(NVL(CUS.CUSTOMER_SSN, ' ')), 0, 6) END AS BIRTH , FN_GET_AGE_NEW(CRYPTO_AES256.DEC_AES(CUS.CUSTOMER_SSN)) AS AGE , SUB.SUBSCRIBER_NO , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS OPEN_DT FROM MSP_JUO_SUB_INFO SUB , MSP_JUO_CUS_INFO CUS WHERE SUB.CUSTOMER_ID = CUS.CUSTOMER_ID AND SUB.SUB_STATUS != 'C'
AND SUB.CONTRACT_NUM = #{contractNum}
AND SUB.SVC_CNTR_NO = #{svcCntrNo}
AND SUB.SUBSCRIBER_NO = #{telNo}
AND 1 = 2

mapper.insert:

        INSERT INTO CMN_KFTC_EVIDENCE 
        /** PayInfoMapper.insertOffline */ 
            (
	             KFTC_EVIDENCE_SEQ /* 증거파일 SEQ */
	           , RGST_DT	/* 등록일자 */
	           , VALID_DT	/* 유효일자 */
	           , CONTRACT_NUM	/* 가입계약번호 */
	           , BAN	/* 청구번호 */
	           , REAL_FILE_PATH	/* 실 파일경로 */
	           , EXT	/* 파일확장자 */
	           , REG_YN	/* 파일등록여부 */
	           , RGST_ID	/*등록ID */
	           , REAL_FILE_NM	/* 실 파일명 */
	           , DPST_BANK_CD  /* 은행코드 */
	           , DPST_ACNT_NUM  /* 계좌번호 */
	           , DPST_PRSN_NM  /* 예금주 */
	           , REGST_ID	/* 등록자ID */
	           , REGST_DTTM	/* 등록일시 */
	           , RVISN_ID	/* 수정자ID */
	           , RVISN_DTTM	/* 수정일시 */
	           , EVIDENCE_TYPE_CD /*파일유형*/
            )
        VALUES 
            (
	            CMN_KFTC_EVIDENCE_SEQ.NEXTVAL
	           , TO_CHAR(SYSDATE, 'YYYYMMDD')
	           , TO_CHAR(SYSDATE + (SELECT B.CD_VAL FROM CMN_GRP_MST A , CMN_GRP_CD_MST B WHERE 1=1 AND A.GRP_ID = B.GRP_ID and a.grp_id = 'CMN0213' AND A.USG_YN = 'Y' AND B.USG_YN = 'Y' AND ROWNUM < 2), 'YYYYMMDD')
	           , #{contractNum}
	           , #{ban}
	           , #{realFilePath}
	           , #{ext}
	           , 'Y'
	           , #{sessionUserId}
	           , #{realFileNm}
	           , #{dpstBankCd}
	           , CRYPTO_AES256.ENC_AES(#{dpstAcntNum})
	           , #{dpstPrsnNm}
	           , #{sessionUserId}
	           , SYSDATE	
	           , #{sessionUserId}
	           , SYSDATE
	           , #{evidenceTypeCd}
            )

INSERT INTO CMN_KFTC_NON_BIND_FILE_HST
/** payinfomapper.insertcmnkftcnonbindfilehst */
(CMN_KFTC_NON_BIND_FILE_HST_SEQ
 , CONTRACT_NUM
 , BAN
 , FILE_NAME
 , FILE_PATH
 , EXT
 , DPST_BANK_CD
 , DPST_ACNT_NUM
 , DPST_PRSN_NM
 , REGST_ID
 , REGST_DTTM
 , RVISN_ID
 , RVISN_DTTM)
VALUES
(CMN_KFTC_NON_BIND_FILE_HST_SEQ.NEXTVAL
 , #{contractNum}
 , #{ban}
 , #{fileName}
 , #{filePath}
 , #{ext}
 , #{dpstBankCd}
 , CRYPTO_AES256.ENC_AES(#{dpstAcntNum})
 , #{dpstPrsnNm}
 , #{regstId}
 , SYSDATE
 , #{rvisnId}
 , SYSDATE)

mapper.select:
SELECT /* PayInfoMapper.payInfoMstList */ A.KFTC_MST_SEQ , A.KFTC_MST_SEQ AS KFTC_MST_SEQ_STR , SUBSTR(A.START_DT, 1,8) AS START_DT , TO_CHAR(TO_DATE(SUBSTR(A.START_DT, 1,8), 'YYYY-MM-DD'), 'YYYY-MM-DD') AS START_DT_STR , SUBSTR(A.END_DT, 1,8) AS END_DT , A.KFTC_FILE_NM , A.STATE_CD , FN_GET_CODENM('CMN0204', A.STATE_CD) AS STATE_NM , A.REGST_ID , A.REGST_DTTM , A.RVISN_ID , A.RVISN_DTTM , A.APPROVAL_ID , FN_GET_USRNM(A.APPROVAL_ID) AS APPROVAL_ID_NM , TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS APPROVAL_DT , A.APPROVAL_MSG , A.STATE_DESC , A.SEND_CNT , NVL(A.APPROVAL_CD, '0001') AS APPROVAL_CD , FN_GET_CODENM('CMN0209', NVL(A.APPROVAL_CD, '0001')) AS APPROVAL_NM , A.RECEIVE_CNT FROM CMN_KFTC_BATCH_MST A WHERE 1 = 1
AND A.STATE_CD = #{stateCd}
AND NVL(A.APPROVAL_CD, '0001') = #{approvalCd}
AND SUBSTR(A.START_DT, 1,8) BETWEEN #{searchStartDt} AND #{searchEndDt}

mapper.update:
	UPDATE /* PayInfoMapper.updateApprovalYn */
		   CMN_KFTC_BATCH_MST
	   SET   RVISN_DTTM = SYSDATE
	        , RVISN_ID = #{sessionUserId}
	        , APPROVAL_ID  = #{sessionUserId}
	        , APPROVAL_DT = SYSDATE
           , STATE_CD = '0001'
           , STATE_CD = '0000'
           , APPROVAL_MSG = #{approvalMsg, jdbcType=VARCHAR} 
           , APPROVAL_CD = #{approvalCd, jdbcType=VARCHAR} 
	 WHERE KFTC_MST_SEQ = #{kftcMstSeq}

mapper.delete:
DELETE 	/* PayInfoMapper.deleteFile */
FROM 	CMN_KFTC_EVIDENCE
WHERE 	KFTC_EVIDENCE_SEQ = #{kftcEvidenceSeq, jdbcType=VARCHAR}

DELETE 	/* PayInfoMapper.deleteFile */
FROM 	CMN_KFTC_EVIDENCE
WHERE 	FILE_ID = #{fileKey, jdbcType=VARCHAR}

mapper.select:
SELECT /* PayInfoMapper.payInfoKtList */ A.KFTC_MST_SEQ, A.KFTC_DTL_SEQ, A.BILL_ACNT_NO, A.CONTRACT_NUM, A.SUBSCRIBER_NO, A.SUB_LINK_NAME, A.AGRE_MNGM_NO, SUBSTR(A.RGST_DT, 1,8) AS RGST_DT, A.AGRE_TYPE_CD, A.SLS_CMPN_CD, A.BANK_CD, FN_GET_CODENM('CMN0001', NVL(A.BANK_CD, '001')) AS BANK_CD_NM, A.CMS_APLY_SRL_NO, A.OUTPYM_SRL_NO, A.BANK_BNKACN_NO, A.REAL_FILE_NAME, A.REAL_FILE_DIR, A.ERROR_CD, FN_GET_CODENM('CMN0207', NVL(A.ERROR_CD, '0002')) AS ERROR_CD_NM, A.READY_CD, A.SEND_CD, A.REGST_ID, A.REGST_DTTM, A.RVISN_ID, A.RVISN_DTTM, B.SUB_STATUS, FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM, B.LST_COM_ACTV_DATE, B.OPEN_AGNT_CD, B.OPEN_AGNT_CD || ' / ' ||FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM, A.FILE_REG_YN, DECODE(NVL(A.FILE_REG_YN, 'N'), 'N' ,'미등록', '등록') AS FILE_REG_YN_NM, C.BAN_ADR_PRIMARY_LN AS ADDR, SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ' )), 1,6) AS USER_SSN, C.BL_BILLING_METHOD, FN_GET_CODENM('MSP0001', NVL(C.BL_BILLING_METHOD, '0001')) AS BL_BILLING_METHOD_NM, B.ON_OFF_TYPE, FN_GET_CODENM('RCP0007', NVL(B.ON_OFF_TYPE, '1')) AS ON_OFF_TYPE_NM, A.APPROVAL_ID, /*검증자ID*/ FN_GET_USRNM(A.APPROVAL_ID) AS APPROVAL_ID_NM, /*검증자명*/ A.APPROVAL_MSG, /*검증내역*/ TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS APPROVAL_DT, /*검증일시*/ NVL(A.APPROVAL_CD, '0002') AS APPROVAL_CD, /*검증결과*/ FN_GET_CODENM('CMN0211', NVL(A.APPROVAL_CD, '0002')) AS APPROVAL_CD_NM, /*검증결과명*/ NVL(A.EVIDENCE_TYPE_CD, '0002') AS EVIDENCE_TYPE_CD, /*파일유형*/ FN_GET_CODENM('CMN0210', NVL(A.EVIDENCE_TYPE_CD, '0002')) AS EVI_CD_NM /*파일유형명*/ FROM CMN_KFTC_BATCH_DTL A, MSP_JUO_SUB_INFO B, MSP_JUO_BAN_INFO C, CMN_KFTC_BATCH_MST D WHERE 1=1 AND A.KFTC_MST_SEQ = D.KFTC_MST_SEQ AND D.STATE_CD != '0050' AND A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND A.BILL_ACNT_NO = C.BAN(+)
AND A.KFTC_MST_SEQ = #{kftcMstSeq}
AND A.RGST_DT BETWEEN #{searchStartDt}||'000000' AND #{searchEndDt}||'235959'
AND A.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND A.SUBSCRIBER_NO = #{searchName}
AND A.FILE_REG_YN = #{fileRegYn}
AND B.OPEN_AGNT_CD = #{orgnId}

