		UPDATE 	CMN_KFTC_BATCH_DTL
		   SET
				 REAL_FILE_NAME      =    #{realFileName}
                ,REAL_FILE_DIR       =    #{realFileDir}
                ,RVISN_ID            =    #{sessionUserId}
                ,RVISN_DTTM          =    SYSDATE
                ,READY_CD            =    '0001'
                ,FILE_REG_YN         =    'Y'
	           , EVIDENCE_TYPE_CD    =    #{evidenceTypeCd}
	           , DPST_BANK_CD        =    #{dpstBankCd}
	           , DPST_ACNT_NUM		 =    CRYPTO_AES256.ENC_AES(#{dpstAcntNum})
	           , DPST_PRSN_NM		 =    #{dpstPrsnNm}
		 WHERE 	KFTC_DTL_SEQ         =    #{kftcDtlSeq}

