UPDATE /* PayInfoMapper.setPayinfoDataSynDTL */ CMN_KFTC_BATCH_DTL
   SET REAL_FILE_NAME = #{realFileNm, jdbcType=VARCHAR}
       , REAL_FILE_DIR = #{realFilePath, jdbcType=VARCHAR}
       , DELETE_FILE_NAME = #{deleteFileName, jdbcType=VARCHAR}
       , FILE_REG_YN = 'Y'
       , READY_CD = '0001'
       , APPROVAL_ID = #{approvalId, jdbcType=VARCHAR}
       , APPROVAL_DT = SYSDATE
       , APPROVAL_MSG = #{approvalMsg, jdbcType=VARCHAR}
       , APPROVAL_CD = #{approvalCd, jdbcType=VARCHAR}
       , RVISN_ID = #{rvisnId, jdbcType=VARCHAR}
       , RVISN_DTTM = SYSDATE
 WHERE KFTC_MST_SEQ = #{kftcMstSeq, jdbcType=NUMERIC}
   AND KFTC_DTL_SEQ = #{kftcDtlSeq, jdbcType=NUMERIC}

	UPDATE /* PayInfoMapper.updateCheYn */
		      CMN_KFTC_EVIDENCE
	   SET   RVISN_DTTM = SYSDATE
	        , RVISN_ID = #{sessionUserId}
	        , APPROVAL_ID  = #{sessionUserId}
	        , APPROVAL_DT = SYSDATE

           , APPROVAL_MSG = #{approvalMsg, jdbcType=VARCHAR}

           , APPROVAL_CD = #{approvalCd, jdbcType=VARCHAR} 
	 WHERE KFTC_EVIDENCE_SEQ = #{kftcEvidenceSeq}

	UPDATE /* PayInfoMapper.updateCheYn */
		      CMN_KFTC_BATCH_DTL
	   SET   RVISN_DTTM = SYSDATE
	        , RVISN_ID = #{sessionUserId}
	        , APPROVAL_ID  = #{sessionUserId}
	        , APPROVAL_DT = SYSDATE
           , APPROVAL_MSG = #{approvalMsg, jdbcType=VARCHAR} 
           , APPROVAL_CD = #{approvalCd, jdbcType=VARCHAR} 
	 WHERE KFTC_DTL_SEQ = #{kftcDtlSeq}

