SELECT * FROM ( SELECT /* PayInfoMapper.orgfileInfoList */ '녹취' AS FILE_TYPE , '0001' AS FILE_TYPE_CD , A.CONTRACT_NUM , B.SUB_LINK_NAME , B.SUBSCRIBER_NO , A.FILE_NAME , A.REGST_ID , TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM --, A.FILE_PATH || A.FILE_NAME AS FILE_PATH , A.DPST_BANK_CD AS BANK_CD , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID ='BNK' AND EXPNSN_STR_VAL1 = A.DPST_BANK_CD) AS BANK_CD_NM , CRYPTO_AES256.DEC_AES(NVL(A.DPST_ACNT_NUM, ' ')) AS BANK_CD_NO , TO_CHAR(A.CMN_KFTC_NON_BIND_FILE_HST_SEQ) AS FILE_ID FROM CMN_KFTC_NON_BIND_FILE_HST A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUBSCRIBER_NO = #{searchName}
AND B.OPEN_AGNT_CD = #{orgnId}
UNION ALL SELECT '이미지' AS FILE_TYPE , '0000' AS FILE_TYPE_CD , A.CONTRACT_NUM , B.SUB_LINK_NAME , B.SUBSCRIBER_NO , A.FILE_ID || '.' || FILE_EXT AS FILE_NAME , A.RGST_PRSN_ID AS REGST_ID , TO_CHAR(A.RGST_DT, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM --, ORIGIN_DIR AS FILE_PATH , A.BANK_CD , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID ='BNK' AND EXPNSN_STR_VAL1 = A.BANK_CD) AS BANK_CD_NM , CRYPTO_AES256.DEC_AES(NVL(A.BANK_CD_NO, ' ')) AS BANK_CD_NO , A.FILE_ID FROM EMV_SCAN_FILE@DL_MCP A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.DOC_ID = 'E0019'
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUBSCRIBER_NO = #{searchName}
AND B.OPEN_AGNT_CD = #{orgnId}
) A ORDER BY A.REGST_DTTM

SELECT /* PayInfoMapper.payInfoMstListEx */ A.KFTC_MST_SEQ , A.KFTC_MST_SEQ AS KFTC_MST_SEQ_STR , SUBSTR(A.START_DT, 1,8) AS START_DT , TO_CHAR(TO_DATE(SUBSTR(A.START_DT, 1,8), 'YYYY-MM-DD'), 'YYYY-MM-DD') AS START_DT_STR , SUBSTR(A.END_DT, 1,8) AS END_DT , A.KFTC_FILE_NM , A.STATE_CD , FN_GET_CODENM('CMN0204', A.STATE_CD) AS STATE_NM , A.REGST_ID , A.REGST_DTTM , A.RVISN_ID , A.RVISN_DTTM , A.APPROVAL_ID , FN_GET_USRNM(A.APPROVAL_ID) AS APPROVAL_ID_NM , TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS APPROVAL_DT , A.APPROVAL_MSG , A.STATE_DESC , A.SEND_CNT , NVL(A.APPROVAL_CD, '0001') AS APPROVAL_CD , FN_GET_CODENM('CMN0209', NVL(A.APPROVAL_CD, '0001')) AS APPROVAL_NM , A.RECEIVE_CNT FROM CMN_KFTC_BATCH_MST A WHERE 1 = 1
AND A.STATE_CD = #{stateCd}
AND NVL(A.APPROVAL_CD, '0001') = #{approvalCd}
AND SUBSTR(A.START_DT, 1,8) BETWEEN #{searchStartDt} AND #{searchEndDt}

SELECT /* PayInfoMapper.payInfoDtlListEx */ A.KFTC_MST_SEQ, A.KFTC_DTL_SEQ, A.BILL_ACNT_NO, A.CONTRACT_NUM, A.SUBSCRIBER_NO, A.SUB_LINK_NAME, A.AGRE_MNGM_NO, SUBSTR(A.RGST_DT, 1,8) AS RGST_DT, A.AGRE_TYPE_CD, A.SLS_CMPN_CD, A.BANK_CD, FN_GET_CODENM('CMN0216', A.BANK_CD) AS BANK_CD_NM, A.CMS_APLY_SRL_NO, A.OUTPYM_SRL_NO, A.BANK_BNKACN_NO, A.REAL_FILE_NAME, A.REAL_FILE_DIR, A.ERROR_CD, FN_GET_CODENM('CMN0207', NVL(A.ERROR_CD, '0002')) AS ERROR_CD_NM, A.READY_CD, A.SEND_CD, A.REGST_ID, A.REGST_DTTM, A.RVISN_ID, A.RVISN_DTTM, B.SUB_STATUS, FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM, B.LST_COM_ACTV_DATE, B.OPEN_AGNT_CD, B.OPEN_AGNT_CD || ' / ' ||FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM, A.FILE_REG_YN, DECODE(NVL(A.FILE_REG_YN, 'N'), 'N' ,'미등록', '등록') AS FILE_REG_YN_NM, C.BAN_ADR_PRIMARY_LN AS ADDR, SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ')), 1,6) AS USER_SSN, C.BL_BILLING_METHOD, FN_GET_CODENM('MSP0001', NVL(C.BL_BILLING_METHOD, '0001')) AS BL_BILLING_METHOD_NM, B.ON_OFF_TYPE, FN_GET_CODENM('RCP0007', NVL(B.ON_OFF_TYPE, '1')) AS ON_OFF_TYPE_NM , A.APPROVAL_ID, /*검증자ID*/ FN_GET_USRNM(A.APPROVAL_ID) AS APPROVAL_ID_NM, /*검증자명*/ A.APPROVAL_MSG, /*검증내역*/ TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS APPROVAL_DT, /*검증일시*/ NVL(A.APPROVAL_CD, '0002') AS APPROVAL_CD, /*검증결과*/ FN_GET_CODENM('CMN0211', NVL(A.APPROVAL_CD, '0002')) AS APPROVAL_CD_NM, /*검증결과명*/ NVL(A.EVIDENCE_TYPE_CD, '0002') AS EVIDENCE_TYPE_CD, /*파일유형*/ FN_GET_CODENM('CMN0210', NVL(A.EVIDENCE_TYPE_CD, '0002')) AS EVI_CD_NM /*파일유형명*/ FROM CMN_KFTC_BATCH_DTL A, MSP_JUO_SUB_INFO B, MSP_JUO_BAN_INFO C, CMN_KFTC_BATCH_MST D WHERE 1=1 AND A.KFTC_MST_SEQ = D.KFTC_MST_SEQ AND D.STATE_CD != '0050' AND A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND A.BILL_ACNT_NO = C.BAN(+)
AND A.KFTC_MST_SEQ = #{kftcMstSeq}
AND A.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND A.SUBSCRIBER_NO = #{searchName}
AND A.FILE_REG_YN = #{fileRegYn}

SELECT /* PayInfoMapper.selectPayinfoKtEx */ A.KFTC_MST_SEQ, A.KFTC_DTL_SEQ, A.BILL_ACNT_NO, A.CONTRACT_NUM, A.SUBSCRIBER_NO, A.SUB_LINK_NAME, A.AGRE_MNGM_NO, SUBSTR(A.RGST_DT, 1,8) AS RGST_DT, A.AGRE_TYPE_CD, A.SLS_CMPN_CD, A.BANK_CD, FN_GET_CODENM('CMN0001', NVL(A.BANK_CD, '001')) AS BANK_CD_NM, A.CMS_APLY_SRL_NO, A.OUTPYM_SRL_NO, A.BANK_BNKACN_NO, A.REAL_FILE_NAME, A.REAL_FILE_DIR, A.ERROR_CD, FN_GET_CODENM('CMN0207', NVL(A.ERROR_CD, '0002')) AS ERROR_CD_NM, A.READY_CD, A.SEND_CD, A.REGST_ID, A.REGST_DTTM, A.RVISN_ID, A.RVISN_DTTM, B.SUB_STATUS, FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM, B.LST_COM_ACTV_DATE, B.OPEN_AGNT_CD, B.OPEN_AGNT_CD || ' / ' ||FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM, A.FILE_REG_YN, DECODE(NVL(A.FILE_REG_YN, 'N'), 'N' ,'미등록', '등록') AS FILE_REG_YN_NM, C.BAN_ADR_PRIMARY_LN AS ADDR, SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ' )), 1,6) AS USER_SSN, C.BL_BILLING_METHOD, FN_GET_CODENM('MSP0001', NVL(C.BL_BILLING_METHOD, '0001')) AS BL_BILLING_METHOD_NM, B.ON_OFF_TYPE, FN_GET_CODENM('RCP0007', NVL(B.ON_OFF_TYPE, '1')) AS ON_OFF_TYPE_NM, A.APPROVAL_ID, /*검증자ID*/ FN_GET_USRNM(A.APPROVAL_ID) AS APPROVAL_ID_NM, /*검증자명*/ A.APPROVAL_MSG, /*검증내역*/ TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS APPROVAL_DT, /*검증일시*/ NVL(A.APPROVAL_CD, '0002') AS APPROVAL_CD, /*검증결과*/ FN_GET_CODENM('CMN0211', NVL(A.APPROVAL_CD, '0002')) AS APPROVAL_CD_NM, /*검증결과명*/ NVL(A.EVIDENCE_TYPE_CD, '0002') AS EVIDENCE_TYPE_CD, /*파일유형*/ FN_GET_CODENM('CMN0210', NVL(A.EVIDENCE_TYPE_CD, '0002')) AS EVI_CD_NM /*파일유형명*/ FROM CMN_KFTC_BATCH_DTL A , MSP_JUO_SUB_INFO B , MSP_JUO_BAN_INFO C , CMN_KFTC_BATCH_MST D WHERE 1=1 AND A.KFTC_MST_SEQ = D.KFTC_MST_SEQ AND D.STATE_CD != '0050' AND A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND A.BILL_ACNT_NO = C.BAN(+)
AND A.KFTC_MST_SEQ = #{kftcMstSeq}
AND A.RGST_DT BETWEEN #{searchStartDt}||'000000' AND #{searchEndDt}||'235959'
AND A.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND A.SUBSCRIBER_NO = #{searchName}
AND A.FILE_REG_YN = #{fileRegYn}
AND B.OPEN_AGNT_CD = #{orgnId}

SELECT * FROM ( SELECT /* PayInfoMapper.orgfileInfoList */ '녹취' AS FILE_TYPE , '0001' AS FILE_TYPE_CD , A.CONTRACT_NUM , B.SUB_LINK_NAME , B.SUBSCRIBER_NO , A.FILE_NAME , A.REGST_ID , TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM --, A.FILE_PATH || A.FILE_NAME AS FILE_PATH , A.DPST_BANK_CD AS BANK_CD , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID ='BNK' AND EXPNSN_STR_VAL1 = A.DPST_BANK_CD) AS BANK_CD_NM , CRYPTO_AES256.DEC_AES(NVL(A.DPST_ACNT_NUM, ' ')) AS BANK_CD_NO FROM CMN_KFTC_NON_BIND_FILE_HST A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUBSCRIBER_NO = #{searchName}
AND B.OPEN_AGNT_CD = #{orgnId}
UNION ALL SELECT '이미지' AS FILE_TYPE , '0000' AS FILE_TYPE_CD , A.CONTRACT_NUM , B.SUB_LINK_NAME , B.SUBSCRIBER_NO, A.FILE_ID || '.' || FILE_EXT AS FILE_NAME , A.RGST_PRSN_ID AS REGST_ID , TO_CHAR(A.RGST_DT, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM --, ORIGIN_DIR AS FILE_PATH , A.BANK_CD , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID ='BNK' AND EXPNSN_STR_VAL1 = A.BANK_CD) AS BANK_CD_NM , CRYPTO_AES256.DEC_AES(NVL(A.BANK_CD_NO, ' ')) AS BANK_CD_NO FROM EMV_SCAN_FILE@DL_MCP A, MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.DOC_ID = 'E0019'
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUBSCRIBER_NO = #{searchName}
AND B.OPEN_AGNT_CD = #{orgnId}
) A ORDER BY A.REGST_DTTM
